import { existsSync, readFileSync, readdirSync, writeFileSync } from "node:fs";
import { join, relative } from "node:path";

const root = process.cwd();
const snapshotPath = join(root, "docs", "library", "public-api.snapshot.txt");
const packageDirectories = ["core", "node", "cli", "validator-ajv", "validator-zod"];
const update = process.argv.includes("--update");
const snapshot = buildSnapshot();

if (update) {
  writeFileSync(snapshotPath, snapshot, "utf8");
  process.stdout.write(`Updated ${relative(root, snapshotPath)}.\n`);
  process.exit(0);
}

if (!existsSync(snapshotPath)) {
  fail("Public API snapshot is missing. Run pnpm run update:api-snapshot.");
}

const expected = normalizeNewlines(readFileSync(snapshotPath, "utf8"));
if (expected !== snapshot) {
  fail("Public API declarations changed. Review the diff, then run pnpm run update:api-snapshot.");
}

function buildSnapshot() {
  const sections = [
    "# Universal Config Engine public declaration snapshot",
    "# Generated by scripts/check-public-api-snapshot.mjs."
  ];

  for (const packageDirectory of packageDirectories) {
    const packageRoot = join(root, "packages", packageDirectory);
    const manifest = JSON.parse(readFileSync(join(packageRoot, "package.json"), "utf8"));
    const distDirectory = join(packageRoot, "dist");
    if (!existsSync(distDirectory)) {
      fail(`Missing ${relative(root, distDirectory)}. Build packages before checking the API snapshot.`);
    }

    sections.push("", `## ${manifest.name}`);
    for (const declarationPath of declarationFiles(distDirectory)) {
      const declarationName = relative(distDirectory, declarationPath).replaceAll("\\", "/");
      const declaration = normalizeDeclaration(readFileSync(declarationPath, "utf8"));
      sections.push("", `### ${declarationName}`, declaration);
    }
  }

  return `${sections.join("\n").trimEnd()}\n`;
}

function declarationFiles(directory) {
  return readdirSync(directory, { withFileTypes: true })
    .flatMap((entry) => {
      const path = join(directory, entry.name);
      return entry.isDirectory() ? declarationFiles(path) : entry.name.endsWith(".d.ts") ? [path] : [];
    })
    .sort((left, right) => left.localeCompare(right));
}

function normalizeDeclaration(value) {
  return normalizeNewlines(value)
    .split("\n")
    .filter((line) => !line.startsWith("//# sourceMappingURL="))
    .join("\n")
    .trimEnd();
}

function normalizeNewlines(value) {
  return value.replaceAll("\r\n", "\n");
}

function fail(message) {
  console.error(message);
  process.exit(1);
}
